const trigger = $('Outlook Trigger').item.json;
const body = trigger.body || {};
const bodyContent = typeof body.content === 'string' ? body.content : '';
const textBody = bodyContent
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim();

const from = trigger.from?.emailAddress?.address || '';
const to = (trigger.toRecipients || []).map(r => r.emailAddress?.address).filter(Boolean);
const cc = (trigger.ccRecipients || []).map(r => r.emailAddress?.address).filter(Boolean);
const subject = trigger.subject || '';
const NL = String.fromCharCode(10);

return [{
  json: {
    messageId: trigger.id,
    conversationId: trigger.conversationId,
    subject,
    from,
    to,
    cc,
    receivedDateTime: trigger.receivedDateTime,
    bodyHtml: bodyContent,
    bodyText: textBody,
    customerEmail: [
      'Subject: ' + subject,
      'From: ' + from,
      'To: ' + to.join(', '),
      cc.length ? 'CC: ' + cc.join(', ') : '',
      'Received: ' + (trigger.receivedDateTime || ''),
      '',
      textBody || bodyContent
    ].filter(Boolean).join(NL),
    searchSeed: [subject, textBody].filter(Boolean).join(' ').slice(0, 3000),
    kbSiteUrl: 'https://tradedoublergroup.sharepoint.com/sites/TechHub',
    kbFolderHint: 'General/AI/TechHub chat bot docs'
  }
}];

