      type: 'json_schema',
      name: 'retrieval_plan',
      strict: true,
      schema: {
        type: 'object',
        additionalProperties: false,
        properties: {
          graphQueryString: { type: 'string' },
          category: { type: 'string' },
          language: { type: 'string' },
          confidence: { type: 'number' },
          escalationLikely: { type: 'boolean' }
        },
        required: ['graphQueryString', 'category', 'language', 'confidence', 'escalationLikely']
      }
    }
  }
} }}

