const item = $input.first().json;
const hits = item.sharePointHits || [];
const NL = String.fromCharCode(10);
const confidence = hits.length === 0 ? 0 : Math.min(0.95, 0.35 + hits.length * 0.08 + (hits.some(h => h.inKbFolder) ? 0.2 : 0));
const context = hits.length ? hits.map((hit, index) => [
  'Source ' + (index + 1) + ': ' + hit.title,
  'Scope: ' + (hit.inKbFolder ? 'TechHub chat bot docs folder' : 'TechHub site fallback'),
  hit.summary ? 'Snippet: ' + hit.summary : '',
  hit.path ? 'Path: ' + hit.path : '',
  hit.webUrl ? 'URL: ' + hit.webUrl : '',
  hit.lastModifiedTime ? 'Last modified: ' + hit.lastModifiedTime : ''
].filter(Boolean).join(NL)).join(NL + NL + '---' + NL + NL) : 'No relevant TechHub SharePoint KB snippets were retrieved. The draft must not invent technical or policy details; it should say we will confirm internally.';

return [{ json: { ...item, retrievalConfidence: confidence, sharePointContext: context, shouldEscalate: hits.length === 0 || confidence < 0.55 } }];

