={{ (() => {
  const NL = String.fromCharCode(10);
  const prompt = [
    'Retrieved SharePoint knowledge:',
    $json.sharePointContext || '',
    '',
    'Retrieval confidence: ' + $json.retrievalConfidence,
    'Escalate if uncertain: ' + $json.shouldEscalate,
    '',
    'Customer email:',
    $json.customerEmail || ''
  ].join(NL);
  return {
    model: 'gpt-5.5',
    input: [
      {
        role: 'system',
        content: [{ type: 'input_text', text: 'You draft professional Outlook email replies for Tradedoubler implementation/support. Use only the retrieved SharePoint knowledge for technical facts. If context is missing or weak, escalate uncertainty instead of guessing. Output only the email body, no subject.' }]
      },
      {
        role: 'user',
        content: [{ type: 'input_text', text: prompt }]
      }
    ]
  };
})() }}

