const drives = $input.first().json.value || [];
const byName = drives.find(d => String(d.name || '').toLowerCase().includes('dokument'))
  || drives.find(d => String(d.name || '').toLowerCase().includes('document'))
  || drives.find(d => String(d.webUrl || '').toLowerCase().includes('delade'))
  || drives.find(d => d.driveType === 'documentLibrary')
  || drives[0];

if (!byName || !byName.id) {
  return [{ json: { error: 'No SharePoint document library drive was returned for TechHub site.', drives } }];
}

return [{
  json: {
    driveId: byName.id,
    driveName: byName.name,
    driveWebUrl: byName.webUrl,
    kbFolderPath: 'General/AI/TechHub chat bot docs',
    folderChildrenUrl: 'https://graph.microsoft.com/v1.0/drives/' + byName.id + '/root:/General/AI/TechHub%20chat%20bot%20docs:/children?$select=id,name,webUrl,file,folder,lastModifiedDateTime,size,parentReference&$top=200'
  }
}];

const folder = $input.first().json || {};
const prep = $('Prepare Email Payload').item.json;
const NL = String.fromCharCode(10);
let retrievalPlan = {};
try {
  const planText = $('OpenAI Extract Retrieval Plan').item.json.output_text
    || (($('OpenAI Extract Retrieval Plan').item.json.output || []).flatMap(o => o.content || []).map(c => c.text).filter(Boolean).join(NL));
  retrievalPlan = JSON.parse(planText || '{}');
} catch (error) {
  retrievalPlan = { graphQueryString: prep.searchSeed, category: 'unknown', confidence: 0.2 };
}

const files = (folder.value || []).filter(item => item.file);
const rawNeedle = [retrievalPlan.graphQueryString, prep.subject, prep.bodyText].filter(Boolean).join(' ').toLowerCase();
const stop = new Set(['the','and','for','with','from','that','this','you','your','are','can','how','what','why','when','where','please','about','into','onto','our','their','tradedoubler']);
const terms = rawNeedle.split(/[^a-z0-9]+/).filter(t => t.length > 2 && !stop.has(t)).slice(0, 40);

const scored = files.map(file => {
  const haystack = [file.name, file.webUrl, file.parentReference?.path].filter(Boolean).join(' ').toLowerCase();
  const score = terms.reduce((sum, term) => sum + (haystack.includes(term) ? 1 : 0), 0);
  return {
    id: file.id,
    name: file.name,
    title: file.name,
    webUrl: file.webUrl || '',
    path: file.parentReference?.path || '',
    filetype: file.name && file.name.includes('.') ? file.name.split('.').pop() : '',
    lastModifiedTime: file.lastModifiedDateTime || '',
    size: file.size || 0,
    score,
    inKbFolder: true,
    summary: score > 0
      ? 'Matched known TechHub KB file by filename/path terms: ' + terms.filter(t => haystack.includes(t)).slice(0, 8).join(', ')
      : 'Known TechHub KB file from the configured SharePoint folder.'
  };
}).sort((a, b) => b.score - a.score || a.name.localeCompare(b.name));

const selected = scored.filter(f => f.score > 0).slice(0, 8);
const fallback = scored.slice(0, 8);
const sharePointHits = selected.length ? selected : fallback;

return [{
  json: {
    ...prep,
    retrievalPlan,
    retrievalMethod: 'known_folder_browse',
    sharePointHits,
    graphRawResultCount: files.length,
    matchedResultCount: selected.length
  }
}];
